+		{"timed out", "network-timeout"},
+		{"not found", "not-found"},
+		{"weird message", "unknown"},
+	}
+	for _, c := range cases {
+		if got := ClassifyError(c.err); got != c.want {
+			t.Fatalf("ClassifyError(%q) got %s want %s", c.err, got, c.want)
+		}
+	}
+}

